import { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import ClientLayout from "../../components/layout/ClientLayout";
import { getOrders } from "../../api/clientApi";
import "../../styles/client/OrderList.css";

const STATUS_META = {
  "РЎРѕР·РґР°РЅ":     { color: "#2563eb", bg: "rgba(37,99,235,0.1)"  },
  "РќР°Р·РЅР°С‡РµРЅ":   { color: "#7c3aed", bg: "rgba(124,58,237,0.1)" },
  "Р’ РїСЂРѕС†РµСЃСЃРµ": { color: "#d97706", bg: "rgba(217,119,6,0.1)"  },
  "Р”РѕСЃС‚Р°РІР»РµРЅ":  { color: "#16a34a", bg: "rgba(22,163,74,0.1)"  },
  "РћС‚РјРµРЅС‘РЅ":    { color: "#dc2626", bg: "rgba(220,38,38,0.1)"  },
};

const FILTERS = ["Р’СЃРµ", "РЎРѕР·РґР°РЅ", "РќР°Р·РЅР°С‡РµРЅ", "Р’ РїСЂРѕС†РµСЃСЃРµ", "Р”РѕСЃС‚Р°РІР»РµРЅ", "РћС‚РјРµРЅС‘РЅ"];

/* в”Ђв”Ђ Safe date в”Ђв”Ђ */
function fmtDate(val) {
  if (!val) return "—";
  const normalized = typeof val === "string" && !val.endsWith("Z") && !val.includes("+") ? val + "Z" : val;
  const d = new Date(normalized);
  return isNaN(d.getTime()) ? "—" : d.toLocaleDateString("ru-RU");
}

function fmtDateTime(val) {
  if (!val) return "—";
  const normalized = typeof val === "string" && !val.endsWith("Z") && !val.includes("+") ? val + "Z" : val;
  const d = new Date(normalized);
  return isNaN(d.getTime()) ? "—" : d.toLocaleString("ru-RU");
}

function StatusBadge({ status }) {
  const m = STATUS_META[status] || { color: "#6b7280", bg: "rgba(107,114,128,0.1)" };
  return <span className="ol-badge" style={{ color: m.color, background: m.bg }}>{status}</span>;
}

/* в”Ђв”Ђ Order detail modal в”Ђв”Ђ */
function OrderModal({ order, onClose, onDetail }) {
  if (!order) return null;
  const sm = STATUS_META[order.status] || { color: "#6b7280", bg: "rgba(107,114,128,0.1)" };
  const isActive = ["РќР°Р·РЅР°С‡РµРЅ", "Р’ РїСЂРѕС†РµСЃСЃРµ"].includes(order.status);
  return (
    <div className="ol-modal-overlay" onClick={onClose}>
      <div className="ol-modal" onClick={e => e.stopPropagation()}>
        <button className="ol-modal-close" onClick={onClose}>
          <i className="bx bx-x" />
        </button>

        {/* Header */}
        <div className="ol-modal-header">
          <div className="ol-modal-id">Р—Р°РєР°Р· #{order.id}</div>
          <span className="ol-modal-badge" style={{ color: sm.color, background: sm.bg }}>
            <span style={{ width:6, height:6, borderRadius:"50%", background: sm.color, display:"inline-block", marginRight:5 }} />
            {order.status}
          </span>
        </div>

        {/* Route */}
        <div className="ol-modal-route">
          <div className="ol-modal-route-row">
            <div className="ol-modal-dot ol-modal-dot--from">A</div>
            <div>
              <div className="ol-modal-route-label">РћС‚РєСѓРґР°</div>
              <div className="ol-modal-route-addr">{order.pickupAddress}</div>
            </div>
          </div>
          <div className="ol-modal-vline" />
          <div className="ol-modal-route-row">
            <div className="ol-modal-dot ol-modal-dot--to">Р‘</div>
            <div>
              <div className="ol-modal-route-label">РљСѓРґР°</div>
              <div className="ol-modal-route-addr">{order.deliveryAddress}</div>
            </div>
          </div>
        </div>

        {/* Meta */}
        <div className="ol-modal-meta">
          <div className="ol-modal-meta-row">
            <span><i className="bx bx-calendar" /> РЎРѕР·РґР°РЅ</span>
            <strong>{fmtDate(order.createdAt)}</strong>
          </div>
          {order.requestedTime && (
            <div className="ol-modal-meta-row">
              <span><i className="bx bx-time" /> Р–РµР»Р°РµРјРѕРµ РІСЂРµРјСЏ</span>
              <strong>{fmtDateTime(order.requestedTime)}</strong>
            </div>
          )}
          {order.courierName && (
            <div className="ol-modal-meta-row">
              <span><i className="bx bx-user" /> РљСѓСЂСЊРµСЂ</span>
              <strong>{order.courierName}</strong>
            </div>
          )}
        </div>

        {/* Actions */}
        <div className="ol-modal-actions">
          {isActive && (
            <button className="ol-modal-btn ol-modal-btn--track"
              onClick={() => { onClose(); onDetail(order.id); }}>
              <i className="bx bx-map-alt" /> РћС‚СЃР»РµРґРёС‚СЊ
            </button>
          )}
          <button className="ol-modal-btn ol-modal-btn--detail"
            onClick={() => { onClose(); onDetail(order.id); }}>
            <i className="bx bx-show" /> РџРѕРґСЂРѕР±РЅР°СЏ РєР°СЂС‚РѕС‡РєР°
          </button>
        </div>
      </div>
    </div>
  );
}

export default function OrdersList() {
  const [orders,   setOrders]   = useState([]);
  const [loading,  setLoading]  = useState(true);
  const [filter,   setFilter]   = useState("Р’СЃРµ");
  const [search,   setSearch]   = useState("");
  const [selected, setSelected] = useState(null);
  const navigate = useNavigate();

  useEffect(() => {
    getOrders()
      .then(data => setOrders(Array.isArray(data) ? data : data.content || []))
      .catch(() => {})
      .finally(() => setLoading(false));
  }, []);

  const filtered = orders.filter(o => {
    const matchFilter = filter === "Р’СЃРµ" || o.status === filter;
    const q = search.toLowerCase();
    const matchSearch = !q
      || String(o.id).includes(q)
      || o.pickupAddress?.toLowerCase().includes(q)
      || o.deliveryAddress?.toLowerCase().includes(q);
    return matchFilter && matchSearch;
  });

  return (
    <ClientLayout>
      <div className="ol-root">
        <div className="ol-hero">
          <div>
            <h1 className="ol-title">РСЃС‚РѕСЂРёСЏ Р·Р°РєР°Р·РѕРІ</h1>
            <p className="ol-sub">{orders.length} Р·Р°РєР°Р·РѕРІ РІСЃРµРіРѕ</p>
          </div>
          <button className="ol-new-btn" onClick={() => navigate("/client/create")}>
            + РќРѕРІС‹Р№ Р·Р°РєР°Р·
          </button>
        </div>

        <div className="ol-toolbar">
          <input className="ol-search"
            placeholder="РџРѕРёСЃРє РїРѕ Р°РґСЂРµСЃСѓ РёР»Рё РЅРѕРјРµСЂСѓ..."
            value={search}
            onChange={e => setSearch(e.target.value)} />
          <div className="ol-filters">
            {FILTERS.map(f => (
              <button key={f}
                className={`ol-filter-btn ${filter === f ? "ol-filter-btn--active" : ""}`}
                onClick={() => setFilter(f)}>{f}</button>
            ))}
          </div>
        </div>

        {loading ? (
          <div className="ol-skels">{[1,2,3,4].map(i => <div key={i} className="ol-skel" />)}</div>
        ) : filtered.length === 0 ? (
          <div className="ol-empty">
            <i className="bx bx-package" />
            <p>{search || filter !== "Р’СЃРµ" ? "РќРµС‚ СЃРѕРІРїР°РґРµРЅРёР№" : "РЈ РІР°СЃ РїРѕРєР° РЅРµС‚ Р·Р°РєР°Р·РѕРІ"}</p>
            {!search && filter === "Р’СЃРµ" && (
              <button className="ol-new-btn" onClick={() => navigate("/client/create")}>
                РЎРѕР·РґР°С‚СЊ РїРµСЂРІС‹Р№ Р·Р°РєР°Р·
              </button>
            )}
          </div>
        ) : (
          <div className="ol-list">
            {filtered.map(o => (
              <div key={o.id} className="ol-card" onClick={() => setSelected(o)}>
                <div className="ol-card-left">
                  <div className="ol-card-id">Р—Р°РєР°Р· #{o.id}</div>
                  <div className="ol-card-route">
                    <div className="ol-addr">
                      <span className="ol-addr-dot ol-addr-dot--from" />
                      <span>{o.pickupAddress}</span>
                    </div>
                    <div className="ol-addr-line" />
                    <div className="ol-addr">
                      <span className="ol-addr-dot ol-addr-dot--to" />
                      <span>{o.deliveryAddress}</span>
                    </div>
                  </div>
                </div>
                <div className="ol-card-right">
                  <StatusBadge status={o.status} />
                  {/* в†ђ РРЎРџР РђР’Р›Р•РќРР•: Р±РµР·РѕРїР°СЃРЅРѕРµ С„РѕСЂРјР°С‚РёСЂРѕРІР°РЅРёРµ РґР°С‚С‹ */}
                  <div className="ol-card-date">{fmtDate(o.createdAt)}</div>
                  <i className="bx bx-chevron-right ol-card-arrow" />
                </div>
              </div>
            ))}
          </div>
        )}

        {/* Modal */}
        <OrderModal
          order={selected}
          onClose={() => setSelected(null)}
          onDetail={(id) => navigate(`/client/orders/${id}`)}
        />
      </div>
    </ClientLayout>
  );
}
